compounddef.initializer:
template<typename T>
concept concepts::MappingWithJacobian =  Mapping<T> && requires
{
    typename T::CoordJacobian;
} && requires(T const& t, typename T::CoordJacobian const& x)
{
    {
        t.jacobian_matrix(x)
        } -> JacobianMatrix<T>;
    {
        t.template jacobian_component<int, int>(x)
        } -> std::floating_point;
    {
        t.jacobian(x)
        } -> std::floating_point;
}
